if (!function_exists('sd_t')) {
  function sd_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('sd_h')) {
  function sd_h($key, $fallback = '') { return htmlspecialchars((string) sd_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('sd_js')) {
  function sd_js($key, $fallback = '') { return json_encode(sd_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
include_once "delivery_report_lib.php";
$defaultFrom=date('Y-m-01');$defaultTo=date('Y-m-d');
$customers=$db->query("SELECT DISTINCT COALESCE(sj.ship_to_party,sj.kode_penerima,so.kode_penerima) kode,COALESCE(NULLIF(c.nama,''),NULLIF(p.nama,''),NULLIF(so.consignee,''),NULLIF(sj.nama_penerima,''),COALESCE(sj.ship_to_party,sj.kode_penerima)) nama FROM surat_jalan sj LEFT JOIN sales_order so ON so.id_sales_order=sj.id_sales_order OR so.no_sales_order=sj.no_sales_order LEFT JOIN customer c ON c.kode_pemasok=COALESCE(sj.ship_to_party,sj.kode_penerima,so.kode_penerima) LEFT JOIN penerima p ON p.kode_penerima=COALESCE(sj.ship_to_party,sj.kode_penerima,so.kode_penerima) WHERE COALESCE(sj.ship_to_party,sj.kode_penerima,so.kode_penerima,'')<>'' ORDER BY nama");
$shipPoints=$db->query("SELECT DISTINCT shipping_point FROM surat_jalan WHERE COALESCE(shipping_point,'')<>'' ORDER BY shipping_point");
$bcTypes=$db->query("SELECT DISTINCT bc_document_type FROM surat_jalan_detail WHERE COALESCE(bc_document_type,'')<>'' ORDER BY bc_document_type");
$sum=dr_summary($db,array('tgl_awal'=>$defaultFrom,'tgl_akhir'=>$defaultTo,'customer'=>'','status'=>'','shipping_point'=>'','bc_type'=>'','gi_status'=>'','keyword'=>''));
?>
