alue=""><?=sd_h('common_all', 'All');?></option><?php foreach($bcTypes as $b){ ?><option value="<?=dr_h($b->bc_document_type);?>"><?=dr_h($b->bc_document_type);?></option><?php } ?></select></div><label class="control-label col-lg-1">GI</label><div class="col-lg-2"><select id="filter_gi_status" class="form-control"><option value=""><?=sd_h('common_all', 'All');?></option><option value="POSTED"><?=sd_h('sales_posted', 'Posted');?></option><option value="REVERSED">Reversed</option><option value="NOT_POSTED">Not Posted</option></select></div><div class="col-lg-2"><input id="filter_keyword" class="form-control" placeholder="SJ, SO, PO, GI, BC"></div></div><div class="form-group"><div class="col-lg-offset-2 col-lg-10"><button id="btn_filter_dr" class="btn btn-primary"><i class="fa fa-filter"></i> <?=sd_h('common_filter', 'Filter');?></button> <button id="btn_reset_dr" class="btn btn-default"><i class="fa fa-refresh"></i> <?=sd_h('common_reset', 'Reset');?></button> <button id="btn_excel_dr" class="btn btn-success"><i class="fa fa-file-excel-o"></i> <?=sd_h('common_export_excel', 'Export Excel');?></button></div></div></form></div></div>
