<script>
function drError(m){$('.isi_warning_delete').text(m||<?=sd_js('sales_delivery_report_process_failed', 'Delivery Report failed to process.');?>);$('.error_data_delete').fadeIn();}
function drFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),customer:$('#filter_customer').val(),status:$('#filter_status').val(),shipping_point:$('#filter_shipping_point').val(),bc_type:$('#filter_bc_type').val(),gi_status:$('#filter_gi_status').val(),keyword:$('#filter_keyword').val()};}
$(function(){if($.fn.datepicker){$('.dr-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_customer,#filter_status,#filter_shipping_point,#filter_bc_type,#filter_gi_status').select2({width:'100%',allowClear:true});}
var dt=$('#dtb_delivery_report').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,scrollX:true,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=sd_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{targets:[8,10],className:'text-right'},{width:'38px',targets:0},{width:'86px',targets:1}],ajax:{url:'<?=base_admin();?>modul/delivery_report/delivery_report_data.php',type:'post',data:function(d){$.extend(d,drFilters());},error:function(xhr){console.log(xhr.responseText);drError(<?=sd_js('sales_delivery_report_load_failed', 'Delivery Report data failed to load.');?>);}}});
$('#btn_filter_dr').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_dr').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_customer,#filter_status,#filter_shipping_point,#filter_bc_type,#filter_gi_status').val('').trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_excel_dr').click(function(){window.location='<?=base_admin();?>modul/delivery_report/delivery_report_action.php?act=excel&'+$.param(drFilters());});
$(document).on('click','.btn-dr-detail',function(){$.post('<?=base_admin();?>modul/delivery_report/delivery_report_action.php?act=detail',{id:$(this).data('id')},function(html){$('#dr_detail_body').html(html);$('#modal_detail_dr').modal('show');}).fail(function(xhr){console.log(xhr.responseText);drError('Detail gagal dibuka.');});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
